const body = $('Webhook').item.json.body;
const question = String(body.question ?? '');
const datasetId = String(body.dataset_id ?? '');

// Verifica token
const tokenData = $('Obter Token PBI').item.json;
if (!tokenData.access_token) {
  const errMsg = typeof tokenData.error_description === 'string' ? tokenData.error_description : JSON.stringify(tokenData);
  return [{ json: { question, datasetId, token: '', measuresList: '', dateColsList: '', textColsList: '', relevantMeasures: [], dateColumns: [], textColumns: [], tokenError: errMsg } }];
}
const token = tokenData.access_token;

// Medidas
const measData = $('Buscar Medidas').item.json;
const measRows = measData.results?.[0]?.tables?.[0]?.rows ?? [];
const allMeasures = measRows
  .map(r => ({ name: r['[Name]'] ?? r['Name'] ?? '', table: r['[Table]'] ?? r['Table'] ?? '' }))
  .filter(m => m.name);

// Colunas
const colData = $input.item.json;
const colRows = colData.results?.[0]?.tables?.[0]?.rows ?? [];
const allColumns = colRows
  .map(r => ({
    name: r['[Name]'] ?? r['Name'] ?? '',
    table: r['[Table]'] ?? r['Table'] ?? '',
    dataType: String(r['[DataType]'] ?? r['DataType'] ?? ''),
    isHidden: Boolean(r['[IsHidden]'] ?? r['IsHidden'] ?? false)
  }))
  .filter(c => c.name && c.table && !c.isHidden);

if (allMeasures.length === 0 && allColumns.length === 0) {
  const errM = measData.error ? JSON.stringify(measData.error) : '';
  const errC = colData.error ? JSON.stringify(colData.error) : '';
  return [{ json: { question, datasetId, token, measuresList: '', dateColsList: '', textColsList: '', relevantMeasures: [], dateColumns: [], textColumns: [], schemaError: errM || errC || 'Nenhuma medida ou coluna encontrada no dataset.' } }];
}

const dateColumns = allColumns.filter(c =>
  c.dataType === '9' || c.dataType === 'DateTime' || c.dataType === 'Date' ||
  c.name.toLowerCase().includes('data') || c.name.toLowerCase().includes('date')
);

const textColumns = allColumns.filter(c =>
  c.dataType === '2' || c.dataType === 'Text' || c.dataType === 'String' ||
  (!c.dataType.match(/^[0-9]+$/) && c.dataType !== 'DateTime' && c.dataType !== 'Date')
);

function normalize(s) {
  return s.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[\s_\-]/g, '');
}
const normQ = normalize(question);
const tokens = normQ.match(/[a-z0-9]{3,}/g) ?? [normQ];

const scored = allMeasures.map(m => {
  const normName = normalize(m.name);
  let score = 0;
  for (const t of tokens) {
    if (normName.includes(t)) score += 2;
    if (normQ.includes(normName)) score += 3;
  }
  if (normName.includes(normQ) || normQ.includes(normName)) score += 5;
  return { m, score };
});
const sorted = scored.filter(s => s.score > 0).sort((a, b) => b.score - a.score);
const relevantMeasures = sorted.length > 0 ? sorted.slice(0, 12).map(s => s.m) : allMeasures.slice(0, 30);

const measuresList = relevantMeasures.map(m => `"${m.name}" (tabela: ${m.table})`).join('\n');
const dateColsList = dateColumns.map(c => `${c.table}[${c.name}]`).join('\n');
const textColsList = textColumns.slice(0, 60).map(c => `${c.table}[${c.name}]`).join('\n');

const isListRequest = /o que (você|vc|voce) sabe|o que (você|vc|voce) (pode|consegue)|quais dados|que dados|me mostra|listar medidas|o que posso perguntar|quais medidas|quais indicadores/i.test(question);

const systemPrompt = 'Você analisa perguntas sobre dados Power BI e retorna JSON com a intenção.\n\nMEDIDAS (use nomes EXATOS):\n' + measuresList + '\n\nCOLUNAS DE DATA:\n' + dateColsList + '\n\nCOLUNAS DE TEXTO (filtros/agrupamentos):\n' + textColsList + '\n\nRetorne UM dos JSONs abaixo:\n1. Valor simples: {"type":"simple","measures":["NomeMedida"]}\n2. Multiplas medidas: {"type":"multi","measures":["Medida1","Medida2"]}\n3. Filtro de periodo: {"type":"period","measures":["NomeMedida"],"date_table":"Tabela","date_col":"Coluna","from_month":1,"from_year":2025,"to_month":1,"to_year":2025}\n   IMPORTANTE: inclua from_year/to_year SOMENTE se o usuario mencionou o ano explicitamente\n4. Filtro por texto: {"type":"text_filter","measures":["NomeMedida"],"filter_table":"Tabela","filter_col":"Coluna","filter_val":"valor"}\n5. Texto + periodo: {"type":"text_date","measures":["NomeMedida"],"filter_table":"Tabela","filter_col":"Coluna","filter_val":"valor","date_table":"Tabela","date_col":"Coluna","from_month":1,"from_year":2025,"to_month":1,"to_year":2025}\n6. Agrupamento: {"type":"group","measures":["NomeMedida"],"group_table":"Tabela","group_col":"Coluna"}\n7. Agrupamento + periodo: {"type":"group_period","measures":["NomeMedida"],"group_table":"Tabela","group_col":"Coluna","date_table":"Tabela","date_col":"Coluna","from_month":1,"from_year":2025,"to_month":1,"to_year":2025}\n8. Ranking: {"type":"ranking","measures":["NomeMedida"],"group_table":"Tabela","group_col":"Coluna","top_n":5,"order":"desc"}\n9. Comparacao de periodos: {"type":"compare","measures":["NomeMedida"],"date_table":"Tabela","date_col":"Coluna","period_a":{"month":1,"year":2025},"period_b":{"month":2,"year":2025}}\n10. Listar medidas: {"type":"list"}\n11. Nao e dado: {"type":"none"}\n\nREGRAS: Use APENAS nomes das listas acima. date_col deve vir de COLUNAS DE DATA. filter_col deve vir de COLUNAS DE TEXTO.';

return [{
  json: {
    question, datasetId, token,
    measuresList, dateColsList, textColsList,
    relevantMeasures, dateColumns, textColumns,
    isListRequest, systemPrompt
  }
}];

const ctx = $('Preparar Contexto').item.json;

if (ctx.tokenError) {
  return [{ json: { queries: [], intent: { type: 'error' }, intentType: 'error', hasDax: false, isList: false, isNone: false, datasetId: ctx.datasetId, token: '', question: ctx.question, relevantMeasures: [], errorMessage: 'Erro ao autenticar no Power BI: ' + ctx.tokenError } }];
}
if (ctx.schemaError) {
  return [{ json: { queries: [], intent: { type: 'error' }, intentType: 'error', hasDax: false, isList: false, isNone: false, datasetId: ctx.datasetId, token: ctx.token, question: ctx.question, relevantMeasures: [], errorMessage: 'Erro ao buscar schema: ' + ctx.schemaError } }];
}

// Se é pergunta de listagem, força list sem depender do OpenAI
if (ctx.isListRequest) {
  return [{ json: { queries: [], intent: { type: 'list' }, intentType: 'list', hasDax: false, isList: true, isNone: false, datasetId: ctx.datasetId, token: ctx.token, question: ctx.question, relevantMeasures: ctx.relevantMeasures } }];
}

const raw = $input.item.json.choices?.[0]?.message?.content ?? '{}';
let intent;
try { intent = JSON.parse(raw); } catch { intent = { type: 'none' }; }

const ref = (table, col) => `${table}[${col}]`;

function dateFilter(table, col, fm, fy, tm, ty) {
  if (!col) return null;
  const r = ref(table, col);
  const conds = [];
  if (fm && (!tm || fm === tm) && (!fy || fy === ty)) {
    conds.push(`MONTH(${r}) = ${fm}`);
    if (fy) conds.push(`YEAR(${r}) = ${fy}`);
  } else {
    if (fm) conds.push(`MONTH(${r}) >= ${fm}`);
    if (fy) conds.push(`YEAR(${r}) >= ${fy}`);
    if (tm) conds.push(`MONTH(${r}) <= ${tm}`);
    if (ty) conds.push(`YEAR(${r}) <= ${ty}`);
  }
  if (conds.length === 0) return null;
  return `FILTER(ALL(${table}), ${conds.join(' && ')})`;
}

let queries = [];
const t = intent.type;

if (t === 'simple' || t === 'multi') {
  if (intent.measures?.length) {
    const cols = intent.measures.map(m => `"${m}", [${m}]`).join(', ');
    queries.push(`EVALUATE ROW(${cols})`);
  }
} else if (t === 'period' && intent.measures?.length && intent.date_col) {
  const df = dateFilter(intent.date_table, intent.date_col, intent.from_month, intent.from_year, intent.to_month, intent.to_year);
  const cols = intent.measures.map(m => df ? `"${m}", CALCULATE([${m}], ${df})` : `"${m}", [${m}]`).join(', ');
  queries.push(`EVALUATE ROW(${cols})`);
} else if (t === 'text_filter' && intent.measures?.length && intent.filter_col) {
  const fRef = ref(intent.filter_table, intent.filter_col);
  const cols = intent.measures.map(m => `"${m}", CALCULATE([${m}], ${fRef} = "${intent.filter_val ?? ''}")`).join(', ');
  queries.push(`EVALUATE ROW(${cols})`);
} else if (t === 'text_date' && intent.measures?.length && intent.filter_col) {
  const fRef = ref(intent.filter_table, intent.filter_col);
  const df = intent.date_col ? dateFilter(intent.date_table, intent.date_col, intent.from_month, intent.from_year, intent.to_month, intent.to_year) : null;
  const filters = [fRef + ` = "${intent.filter_val ?? ''}"`, df].filter(Boolean).join(', ');
  const cols = intent.measures.map(m => `"${m}", CALCULATE([${m}], ${filters})`).join(', ');
  queries.push(`EVALUATE ROW(${cols})`);
} else if (t === 'group' && intent.measures?.length && intent.group_col) {
  const gRef = ref(intent.group_table, intent.group_col);
  const measCols = intent.measures.map(m => `"${m}", [${m}]`).join(', ');
  queries.push(`EVALUATE SUMMARIZECOLUMNS(${gRef}, ${measCols}) ORDER BY [${intent.measures[0]}] DESC`);
} else if (t === 'group_period' && intent.measures?.length && intent.group_col && intent.date_col) {
  const gRef = ref(intent.group_table, intent.group_col);
  const df = dateFilter(intent.date_table, intent.date_col, intent.from_month, intent.from_year, intent.to_month, intent.to_year);
  const measCols = df ? intent.measures.map(m => `"${m}", CALCULATE([${m}], ${df})`).join(', ') : intent.measures.map(m => `"${m}", [${m}]`).join(', ');
  queries.push(`EVALUATE SUMMARIZECOLUMNS(${gRef}, ${measCols}) ORDER BY [${intent.measures[0]}] DESC`);
} else if (t === 'ranking' && intent.measures?.length && intent.group_col) {
  const gRef = ref(intent.group_table, intent.group_col);
  const n = intent.top_n ?? 10;
  const ord = intent.order === 'asc' ? 'ASC' : 'DESC';
  queries.push(`EVALUATE TOPN(${n}, SUMMARIZECOLUMNS(${gRef}, "${intent.measures[0]}", [${intent.measures[0]}]), [${intent.measures[0]}], ${ord})`);
} else if (t === 'compare' && intent.measures?.length && intent.date_col) {
  const pa = intent.period_a;
  const pb = intent.period_b;
  const dfA = dateFilter(intent.date_table, intent.date_col, pa.month, pa.year, pa.month, pa.year);
  const dfB = dateFilter(intent.date_table, intent.date_col, pb.month, pb.year, pb.month, pb.year);
  const me = intent.measures[0];
  const partA = dfA ? `CALCULATE([${me}], ${dfA})` : `[${me}]`;
  const partB = dfB ? `CALCULATE([${me}], ${dfB})` : `[${me}]`;
  queries.push(`EVALUATE ROW("Periodo A", ${partA}, "Periodo B", ${partB})`);
}

return [{
  json: {
    queries, intent, intentType: t,
    hasDax: queries.length > 0,
    isList: t === 'list',
    isNone: t === 'none',
    datasetId: ctx.datasetId,
    token: ctx.token,
    question: ctx.question,
    relevantMeasures: ctx.relevantMeasures
  }
}];

const daxCtx = $('Construir DAX').item.json;
const results = $input.item.json.results ?? [];

let formatted = '';
let hasValue = false;

results.forEach(res => {
  const rows = res?.tables?.[0]?.rows ?? [];
  if (rows.length === 0) return;
  const keys = Object.keys(rows[0]);
  const cleanKeys = keys.map(k => k.replace(/^\[|\]$/g, ''));
  if (rows.length === 1) {
    const row = rows[0];
    const pairs = keys.map((k, i) => `${cleanKeys[i]}: ${row[k] ?? 'sem valor'}`);
    formatted += pairs.join('\n') + '\n';
    if (keys.some(k => row[k] !== null && row[k] !== undefined && row[k] !== '')) hasValue = true;
  } else {
    const header = cleanKeys.join(' | ');
    const lines = rows.slice(0, 80).map(row => keys.map(k => String(row[k] ?? '')).join(' | '));
    formatted += header + '\n' + lines.join('\n');
    if (rows.length > 80) formatted += `\n... e mais ${rows.length - 80} linhas.`;
    formatted += '\n';
    hasValue = true;
  }
});

const formattedTrim = formatted.trim() || null;

const formatBody = JSON.stringify({
  model: 'gpt-4o-mini',
  max_tokens: 600,
  messages: [
    {
      role: 'system',
      content: 'Você é a SIL, assistente de inteligência analítica da Solução Inteligente. Responda SEMPRE em português brasileiro.\n\nDADOS DO POWER BI:\n' + (formattedTrim ?? 'Nenhum dado.') + '\n\nREGRAS:\n- Use os dados acima para responder. Formate números como R$ 1.234,56 ou % quando aplicável.\n- Se for lista/tabela: apresente organizado com markdown.\n- Se for comparação: mostre os dois valores e a diferença percentual.\n- Seja direto e objetivo.\n- NUNCA gere código DAX, SQL, fórmulas ou explique como calcular.\n- NUNCA invente valores.'
    },
    { role: 'user', content: daxCtx.question }
  ]
});

return [{
  json: {
    formatted: formattedTrim,
    hasValue,
    question: daxCtx.question,
    intent: daxCtx.intent,
    intentType: daxCtx.intentType,
    formatBody
  }
}];

const daxCtx = $('Construir DAX').item.json;
const ctx = $('Preparar Contexto').item.json;
const classifyRaw = $('OpenAI - Classificar Intenção').item.json;

// DEBUG: retorna info do que aconteceu
const debug = { intentType: daxCtx.intentType, intent: daxCtx.intent, openaiStatus: classifyRaw?.error ? 'ERRO: ' + JSON.stringify(classifyRaw.error) : (classifyRaw?.choices ? 'OK' : 'SEM_CHOICES'), openaiRaw: classifyRaw?.choices?.[0]?.message?.content ?? classifyRaw?.error?.message ?? JSON.stringify(classifyRaw).slice(0, 200), measuresCount: ctx.relevantMeasures?.length ?? 0 };

let message;
if (daxCtx.errorMessage) {
  message = daxCtx.errorMessage;
} else if (daxCtx.isList) {
  const lista = (ctx.relevantMeasures ?? []).map(m => `- ${m.name}`).join('\n');
  message = lista
    ? `Tenho acesso às seguintes medidas no dataset:\n${lista}\n\nExemplos de perguntas:\n- Qual é o total de ${ctx.relevantMeasures?.[0]?.name ?? 'Vendas'}?\n- Me mostre o ${ctx.relevantMeasures?.[1]?.name ?? 'Faturamento'} de janeiro\n- Ranking por ${ctx.relevantMeasures?.[0]?.name ?? 'indicador'}`
    : 'Não encontrei medidas no dataset.';
} else {
  message = 'Não encontrei dados para essa pergunta. Tente usar o nome exato do indicador ou seja mais específico.';
}

return [{ json: { message, source: 'n8n', debug } }];
